mapper.select:
SELECT i.id, i.job_definition_id, i.log_path, i.runtime_config, i.start_time, i.end_time, i.run_mode, i.job_status, i.engine_job_id, i.job_type, i.error_message,
d.job_name, d.job_desc, d.job_version, d.source_type, d.sink_type, d.parallelism,
m.read_row_count AS readRowCount, m.write_row_count AS writeRowCount, m.read_qps AS readQps, m.write_qps AS writeQps, m.record_delay AS recordDelay, i.job_status AS metricsStatus, d.source_table AS sourceTable, d.sink_table AS sinkTable,
s.cron_expression AS cronExpression, s.schedule_status AS scheduleStatus, s.last_schedule_time AS lastScheduleTime, s.next_schedule_time AS nextScheduleTime
FROM t_seatunnel_job_instance i
LEFT JOIN t_seatunnel_job_definition d ON i.job_definition_id = d.id
LEFT JOIN t_seatunnel_job_metrics m ON i.id = m.job_instance_id
LEFT JOIN t_seatunnel_job_schedule s ON i.job_definition_id = s.job_definition_id
AND i.job_status = #{dto.jobStatus}
AND i.job_definition_id = #{dto.jobDefinitionId}
AND i.run_mode = #{dto.runMode}
AND ( d.job_name LIKE CONCAT('%', #{dto.keyword}, '%') OR i.job_engine_id LIKE CONCAT('%', #{dto.keyword}, '%') OR i.error_message LIKE CONCAT('%', #{dto.keyword}, '%') )
AND i.create_time >= #{dto.queryStartTime}
AND i.create_time <= #{dto.queryEndTime}
ORDER BY i.start_time DESC
